import{_ as l,c as e,o as i,ah as r}from"./chunks/framework.Cnj7lwEt.js";const f=JSON.parse('{"title":"CasaOS","description":"","frontmatter":{},"headers":[],"relativePath":"github汇总/个人云系统/CasaOS-个人云系统.md","filePath":"github汇总/个人云系统/CasaOS-个人云系统.md"}'),h={name:"github汇总/个人云系统/CasaOS-个人云系统.md"};function t(s,a,o,n,c,d){return i(),e("div",null,a[0]||(a[0]=[r('<h1 id="casaos" tabindex="-1">CasaOS <a class="header-anchor" href="#casaos" aria-label="Permalink to “CasaOS”">​</a></h1><h2 id="作者或组织名" tabindex="-1">作者或组织名 <a class="header-anchor" href="#作者或组织名" aria-label="Permalink to “作者或组织名”">​</a></h2><p>IceWhale Tech</p><h2 id="项目类别" tabindex="-1">项目类别 <a class="header-anchor" href="#项目类别" aria-label="Permalink to “项目类别”">​</a></h2><p>个人云系统</p><h2 id="核心痛点" tabindex="-1">核心痛点 <a class="header-anchor" href="#核心痛点" aria-label="Permalink to “核心痛点”">​</a></h2><p>搭建个人云需要很强的技术能力或复杂系统</p><h2 id="主要功能" tabindex="-1">主要功能 <a class="header-anchor" href="#主要功能" aria-label="Permalink to “主要功能”">​</a></h2><ul><li>简单易用的家用个人云操作系统</li><li>专为家庭场景设计的友好UI，无需代码、无需表单</li><li>支持多种硬件（ZimaBoard、NUC、树莓派、旧电脑）</li><li>支持多种基础系统（Ubuntu、Debian、树莓派OS、CentOS）</li><li>应用商店，精选应用一键安装</li><li>支持超过10万个Docker生态应用</li><li>优雅的文件管理，所见即所得</li></ul><h2 id="项目亮点" tabindex="-1">项目亮点 <a class="header-anchor" href="#项目亮点" aria-label="Permalink to “项目亮点”">​</a></h2><ul><li>友好UI，专为家庭场景设计，无需代码</li><li>多硬件支持，ZimaBoard、NUC、树莓派、旧电脑都能用</li><li>多基础系统兼容，Ubuntu、Debian、树莓派OS、CentOS都支持</li><li>应用商店，精选应用一键安装（Nextcloud、HomeAssistant、AdGuard、Jellyfin等）</li><li>支持超过10万个Docker生态应用</li><li>优雅的文件管理，所见即所得</li><li>活跃的社区和生态</li></ul><h2 id="荣誉信息" tabindex="-1">荣誉信息 <a class="header-anchor" href="#荣誉信息" aria-label="Permalink to “荣誉信息”">​</a></h2><p>README/仓库信息中未明确说明</p><h2 id="项目地址" tabindex="-1">项目地址 <a class="header-anchor" href="#项目地址" aria-label="Permalink to “项目地址”">​</a></h2><p><a href="https://github.com/IceWhaleTech/CasaOS" target="_blank" rel="noreferrer">https://github.com/IceWhaleTech/CasaOS</a> <a href="/网络环境.html">海外网络环境配置 →</a></p><h2 id="安装或部署教程" tabindex="-1">安装或部署教程 <a class="header-anchor" href="#安装或部署教程" aria-label="Permalink to “安装或部署教程”">​</a></h2><h3 id="教程适用对象与环境范围" tabindex="-1">教程适用对象与环境范围 <a class="header-anchor" href="#教程适用对象与环境范围" aria-label="Permalink to “教程适用对象与环境范围”">​</a></h3><p>适用于想在家里搭建个人云的普通用户和技术爱好者，支持多种硬件和基础系统</p><h3 id="前置条件检查" tabindex="-1">前置条件检查 <a class="header-anchor" href="#前置条件检查" aria-label="Permalink to “前置条件检查”">​</a></h3><ol><li>硬件要求：ZimaBoard、NUC、树莓派或旧电脑</li><li>系统要求：Ubuntu、Debian、树莓派OS或CentOS</li><li>网络连接：可访问互联网</li></ol><h3 id="主路径-一键安装脚本" tabindex="-1">主路径：一键安装脚本 <a class="header-anchor" href="#主路径-一键安装脚本" aria-label="Permalink to “主路径：一键安装脚本”">​</a></h3><ul><li>步骤目标：使用一键安装脚本安装CasaOS</li><li>执行位置：终端/命令行</li><li>完整命令：<code>curl -fsSL https://get.casaos.io | bash</code></li><li>成功标志：安装完成后，访问http://[你的设备IP]:80</li><li>失败处理：检查系统是否兼容，网络连接是否正常，查看安装日志排查问题</li></ul><h3 id="安装成功验证" tabindex="-1">安装成功验证 <a class="header-anchor" href="#安装成功验证" aria-label="Permalink to “安装成功验证”">​</a></h3><ol><li>访问地址：http://[你的设备IP]:80</li><li>官方网站：<a href="https://casaos.io" target="_blank" rel="noreferrer">https://casaos.io</a> <a href="/网络环境.html">海外网络环境配置 →</a></li></ol><h3 id="常见错误排查" tabindex="-1">常见错误排查 <a class="header-anchor" href="#常见错误排查" aria-label="Permalink to “常见错误排查”">​</a></h3><ol><li>现象：安装失败 <ul><li>可能原因：系统不兼容或网络问题</li><li>解决步骤：检查系统是否为支持的版本，检查网络连接</li></ul></li><li>现象：无法访问Web界面 <ul><li>可能原因：防火墙或端口占用</li><li>解决步骤：检查防火墙设置，确认端口80未被占用</li></ul></li><li>现象：应用安装失败 <ul><li>可能原因：网络或存储空间问题</li><li>解决步骤：检查网络连接，确认有足够的存储空间</li></ul></li></ol><h3 id="信息缺失说明" tabindex="-1">信息缺失说明 <a class="header-anchor" href="#信息缺失说明" aria-label="Permalink to “信息缺失说明”">​</a></h3><p>如需深入了解详细配置和使用方法，可访问官方网站：<a href="https://casaos.io" target="_blank" rel="noreferrer">https://casaos.io</a> <a href="/网络环境.html">海外网络环境配置 →</a></p>',28)]))}const p=l(h,[["render",t]]);export{f as __pageData,p as default};
